#include <bits/stdc++.h>
using namespace std;

long long exgcd(long long a,long long b,long long &x,long long &y){
    if(b==0){
        x=1,y=0;
        return a;
    }
    long long gcd=exgcd(b,a%b,x,y),t=x;
    x=y,y=t-a/b*y;
    return gcd;
}

int main(){
    int x,y,m,n,l;
    scanf("%d%d%d%d%d",&x,&y,&m,&n,&l); 
    x%=l,y%=l;
    long long t,k;
	long long gcd=exgcd(m-n,l,t,k);
    long long lcm=1LL*(m-n)*l/gcd;
    if((y-x)%gcd)
        printf("Impossible");
    else{
        t=(t*((y-x)/gcd)%l+l)%l;
        k=(k*((y-x)/gcd)%l+l)%l;
        t%=lcm/(m-n);
        printf("%lld",t);
    }
    return 0;
}
